const rows = Array.from(document.querySelectorAll('.ant-table-tbody > tr.ant-table-row'));
const data = rows.map(tr => {
  const id = tr.getAttribute('data-row-key');
  const name = tr.querySelector('td:nth-child(1) a')?.innerText.trim() || '';
  const departmentCode = tr.querySelector('td:nth-child(2) span.font-mono:first-child')?.innerText.trim() || '';
  const divisionCode = tr.querySelector('td:nth-child(2) span.font-mono:last-child')?.innerText.trim() || '';
  const leaderName = tr.querySelector('td:nth-child(3) .text-slate-700')?.innerText.trim() || '';
  const leaderLdap = tr.querySelector('td:nth-child(3) span.font-mono')?.innerText.trim() || '';
  const status = tr.querySelector('td:nth-child(4) .pill')?.innerText.trim() || '';
  const employeeCount = tr.querySelector('td:nth-child(5) span')?.innerText.trim() || '0';
  return { id, name, departmentCode, divisionCode, leaderName, leaderLdap, status, employeeCount };
}).filter(r => r.id);
automaSetVariable('scraped_sales_teams', data);
automaNextBlock({ teams: data });
